#include <iostream>
#define int long long

using namespace std;

class Solution {
public:
    bool isPrime(int n) {
        if (n <= 1) return false;
        if (n == 2) return true;
        if (n % 2 == 0) return false;
        int max_div = sqrt(n) + 1;
        for (int i = 3; i <= max_div; i += 2)
            if (n % i == 0) return false;
        return true;
    }

    void solve() {
        int n;
        cin >> n;
        for (int i = 0; i < n; i++) {
            int num;
            cin >> num;
            cout << isPrime(num) << endl;
        }
    }
};

